<!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></div><!--]--><!--]--></div><!----><!----><!----><!----><span></span><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></div><!--]--><!--[--><div class=\"fullSection noBorder radius0 none c-section c-wrapper section-FpRjACtFg\" style=\"\" id=\"section-FpRjACtFg\"><!----><!----><div class=\"inner\"><!----><!--[--><!--[--><div class=\"row-align-center noBorder radius0 none c-row c-wrapper row-A_x2y1vWns\" id=\"row-A_x2y1vWns\"><!----><!----><div class=\"inner\"><!----><!--[--><!--[--><div class=\"noBorder radius0 none c-column c-wrapper col-JqtAqkuJaF\" id=\"col-JqtAqkuJaF\"><!----><!----><div class=\"vertical inner\"><!----><!--[--><!--[--><div id=\"custom-code-M2xEwVmNfBQ\" class=\"c-custom-code c-wrapper custom-code-M2xEwVmNfBQ\"><!----><!----><!----><!----><!----><!----><!----><span></span><div id=\"custom-code-M2xEwVmNfBQ\" class=\"custom-code-container ccustom-code-M2xEwVmNfBQ\"><!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com/\">\n<link href=\"https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700;800&amp;family=DM+Sans:wght@400;500;600;700&amp;display=swap\" rel=\"stylesheet\">\n<style>\n  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n  :root {\n    --purple: #7c3aed;\n    --purple-pale: #fdf3ff;\n    --purple-border: #ce93d8;\n    --pink: #ce93d8;\n    --black: #1a1a1a;\n    --gray-dark: #3d3d3d;\n    --gray-mid: #6b6b6b;\n    --bg: #f8f9fa;\n    --white: #ffffff;\n    --radius: 16px;\n    --radius-sm: 10px;\n    --shadow: 0 4px 24px rgba(124,58,237,0.08);\n    --shadow-card: 0 2px 20px rgba(0,0,0,0.07);\n  }\n  html { scroll-behavior: smooth; }\n  body { font-family: 'DM Sans', sans-serif; background: var(--bg); color: var(--black); -webkit-font-smoothing: antialiased; }\n\n  /* NAV */\n  nav { background: var(--white); border-bottom: 1px solid #ece8f5; padding: 16px 24px; display: flex; align-items: center; justify-content: space-between; position: sticky; top: 0; z-index: 100; }\n  .nav-logo img { height: 36px; width: auto; }\n  .nav-cta { background: var(--purple); color: var(--white); border: none; border-radius: 50px; padding: 10px 20px; font-size: 14px; font-weight: 600; cursor: pointer; text-decoration: none; font-family: 'DM Sans', sans-serif; white-space: nowrap; }\n  .nav-cta:hover { opacity: 0.88; }\n  @media (max-width: 480px) { .nav-logo img { height: 28px; } .nav-cta { padding: 9px 14px; font-size: 13px; } }\n\n\n  /* MAIN CONTENT */\n  .blog-wrap { max-width: 1100px; margin: 0 auto; padding: 52px 20px 80px; }\n\n  /* LOADING / ERROR STATES */\n  .state-box { text-align: center; padding: 80px 20px; }\n  .spinner { width: 40px; height: 40px; border: 3px solid var(--purple-pale); border-top-color: var(--purple); border-radius: 50%; animation: spin 0.7s linear infinite; margin: 0 auto 16px; }\n  @keyframes spin { to { transform: rotate(360deg); } }\n  .state-box p { color: var(--gray-mid); font-size: 15px; }\n  .error-box { background: #fff5f5; border: 1.5px solid #fca5a5; border-radius: var(--radius-sm); padding: 20px 24px; color: #c0392b; font-size: 14px; text-align: center; }\n\n  /* CATEGORY FILTERS */\n  .filters { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 36px; }\n  .filter-btn { background: var(--white); border: 1.5px solid #ece8f5; border-radius: 50px; padding: 8px 18px; font-size: 13px; font-weight: 600; color: var(--gray-mid); cursor: pointer; font-family: 'DM Sans', sans-serif; transition: all 0.2s; }\n  .filter-btn:hover { border-color: var(--purple-border); color: var(--purple); }\n  .filter-btn.active { background: var(--purple); border-color: var(--purple); color: var(--white); }\n\n  /* FEATURED POST */\n  .featured-section { margin-bottom: 52px; }\n  .featured-label { font-size: 11px; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase; color: var(--pink); margin-bottom: 14px; display: flex; align-items: center; gap: 8px; }\n  .featured-label::after { content: ''; flex: 1; height: 1px; background: var(--purple-border); opacity: 0.4; }\n\n  .featured-card { background: var(--white); border-radius: var(--radius); overflow: hidden; box-shadow: var(--shadow-card); display: grid; grid-template-columns: 1fr 1fr; border: 1.5px solid #ece8f5; transition: transform 0.25s, box-shadow 0.25s; text-decoration: none; }\n  .featured-card:hover { transform: translateY(-3px); box-shadow: 0 8px 40px rgba(124,58,237,0.13); }\n  @media (max-width: 680px) { .featured-card { grid-template-columns: 1fr; } }\n  .featured-img-wrap { position: relative; overflow: hidden; min-height: 280px; }\n  .featured-img-wrap img { width: 100%; height: 100%; object-fit: cover; display: block; transition: transform 0.4s; }\n  .featured-card:hover .featured-img-wrap img { transform: scale(1.03); }\n  .featured-badge { position: absolute; top: 16px; left: 16px; background: var(--purple); color: var(--white); font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.07em; padding: 5px 12px; border-radius: 50px; }\n  .featured-body { padding: 36px 36px 32px; display: flex; flex-direction: column; justify-content: center; }\n  @media (max-width: 680px) { .featured-body { padding: 24px 22px; } }\n  .featured-cat { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.08em; color: var(--pink); margin-bottom: 10px; }\n  .featured-body h2 { font-family: 'Poppins', sans-serif; font-weight: 700; font-size: clamp(20px, 2.5vw, 28px); color: var(--black); line-height: 1.25; margin-bottom: 14px; }\n  .featured-body p { font-size: 15px; color: var(--gray-mid); line-height: 1.65; margin-bottom: 24px; flex: 1; }\n  .featured-meta { display: flex; align-items: center; gap: 10px; margin-bottom: 24px; }\n  .featured-meta img { width: 32px; height: 32px; border-radius: 50%; object-fit: cover; object-position: top; border: 2px solid var(--purple-border); }\n  .featured-meta span { font-size: 13px; color: var(--gray-mid); }\n  .featured-meta strong { color: var(--black); }\n  .read-btn { display: inline-flex; align-items: center; gap: 8px; background: var(--purple); color: var(--white); border-radius: 50px; padding: 12px 24px; font-family: 'Poppins', sans-serif; font-size: 14px; font-weight: 600; text-decoration: none; align-self: flex-start; transition: opacity 0.2s; }\n  .read-btn:hover { opacity: 0.88; }\n  .read-btn svg { width: 14px; height: 14px; transition: transform 0.2s; }\n  .read-btn:hover svg { transform: translateX(3px); }\n\n  /* POSTS GRID */\n  .grid-section {}\n  .grid-label { font-size: 11px; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase; color: var(--pink); margin-bottom: 20px; display: flex; align-items: center; gap: 8px; }\n  .grid-label::after { content: ''; flex: 1; height: 1px; background: var(--purple-border); opacity: 0.4; }\n  .posts-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 24px; }\n\n  .post-card { background: var(--white); border-radius: var(--radius); overflow: hidden; box-shadow: var(--shadow-card); border: 1.5px solid #ece8f5; text-decoration: none; display: flex; flex-direction: column; transition: transform 0.25s, box-shadow 0.25s; animation: fadeUp 0.4s ease both; }\n  .post-card:hover { transform: translateY(-3px); box-shadow: 0 8px 36px rgba(124,58,237,0.12); border-color: var(--purple-border); }\n  @keyframes fadeUp { from { opacity: 0; transform: translateY(16px); } to { opacity: 1; transform: translateY(0); } }\n  .post-thumb { position: relative; overflow: hidden; aspect-ratio: 16/9; }\n  .post-thumb img { width: 100%; height: 100%; object-fit: cover; display: block; transition: transform 0.35s; }\n  .post-card:hover .post-thumb img { transform: scale(1.04); }\n  .post-cat-badge { position: absolute; bottom: 10px; left: 10px; font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.07em; padding: 4px 10px; border-radius: 50px; background: rgba(124,58,237,0.85); color: var(--white); backdrop-filter: blur(4px); }\n  .post-body { padding: 20px 22px 22px; flex: 1; display: flex; flex-direction: column; }\n  .post-body h3 { font-family: 'Poppins', sans-serif; font-weight: 700; font-size: 16px; color: var(--black); line-height: 1.35; margin-bottom: 10px; }\n  .post-body p { font-size: 14px; color: var(--gray-mid); line-height: 1.6; flex: 1; margin-bottom: 16px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }\n  .post-footer { display: flex; align-items: center; justify-content: space-between; padding-top: 14px; border-top: 1px solid #f0eff4; }\n  .post-date { font-size: 12px; color: var(--gray-mid); }\n  .post-arrow { width: 30px; height: 30px; background: var(--purple-pale); border-radius: 50%; display: flex; align-items: center; justify-content: center; color: var(--purple); font-size: 14px; transition: background 0.2s; }\n  .post-card:hover .post-arrow { background: var(--purple); color: var(--white); }\n\n  /* EMPTY STATE */\n  .empty-state { text-align: center; padding: 60px 20px; color: var(--gray-mid); }\n  .empty-state p { font-size: 15px; }\n\n  /* BOTTOM CTA */\n  .bottom-cta { background: linear-gradient(135deg, #7c3aed 0%, #9B3DE8 100%); border-radius: var(--radius); padding: 48px 28px; text-align: center; margin-top: 60px; position: relative; overflow: hidden; }\n  .bottom-cta::before { content: ''; position: absolute; top: -50px; right: -50px; width: 200px; height: 200px; background: rgba(255,255,255,0.05); border-radius: 50%; }\n  .bottom-cta h3 { font-family: 'Poppins', sans-serif; font-size: clamp(22px, 3vw, 30px); font-weight: 700; color: var(--white); margin-bottom: 10px; position: relative; }\n  .bottom-cta p { color: rgba(255,255,255,0.8); font-size: 16px; margin-bottom: 28px; position: relative; max-width: 480px; margin-left: auto; margin-right: auto; }\n  .bottom-cta-btns { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; position: relative; }\n  .btn-white { background: var(--white); color: var(--purple); border-radius: 50px; padding: 14px 28px; font-size: 15px; font-weight: 700; text-decoration: none; font-family: 'Poppins', sans-serif; transition: opacity 0.2s; }\n  .btn-white:hover { opacity: 0.92; }\n  .btn-ghost { background: transparent; color: var(--white); border: 2px solid rgba(255,255,255,0.45); border-radius: 50px; padding: 14px 28px; font-size: 15px; font-weight: 600; text-decoration: none; font-family: 'DM Sans', sans-serif; }\n  .btn-ghost:hover { border-color: rgba(255,255,255,0.9); }\n\n\n  /* POST COUNT */\n  .post-count { font-size: 13px; color: var(--gray-mid); margin-bottom: 20px; }\n  .post-count strong { color: var(--black); }\n</style>\n</head>\n<body>\n\n<!-- BLOG CONTENT -->\n<div class=\"blog-wrap\">\n  <div id=\"blog-root\">\n    <div class=\"state-box\">\n      <div class=\"spinner\"></div>\n      <p>Loading articles...</p>\n    </div>\n  </div>\n\n  <!-- BOTTOM CTA -->\n  <div class=\"bottom-cta\">\n    <h3>Not sure what your options are?</h3>\n    <p>Talk to a CDPS-certified agent — free, confidential, and no obligation. We will tell you the truth about your situation.</p>\n    <div class=\"bottom-cta-btns\">\n      <a href=\"contactus.html\" class=\"btn-white\">Get My Free Options Review</a>\n      <a href=\"tel:4352443210\" class=\"btn-ghost\">(435) 244-3210</a>\n    </div>\n  </div>\n</div>\n\n\n<script>\n  const AIRTABLE_TOKEN = '';\n  const BASE_ID = 'appC68E50Mw6NqLQQ';\n  const TABLE_NAME = 'Blog Posts';\n\n  let allPosts = [];\n  let activeFilter = 'All';\n\n  async function fetchPosts() {\n    const url = `https://api.airtable.com/v0/${BASE_ID}/${encodeURIComponent(TABLE_NAME)}?sort[0][field]=Publish Date&sort[0][direction]=desc`;\n    const res = await fetch(url, {\n      headers: { Authorization: `Bearer ${AIRTABLE_TOKEN}` }\n    });\n    if (!res.ok) throw new Error(`Airtable error: ${res.status}`);\n    const data = await res.json();\n    return data.records.map(r => ({\n      id: r.id,\n      title: r.fields['Title'] || '',\n      slug: r.fields['Slug'] || '#',\n      description: r.fields['Description'] || '',\n      thumbnail: r.fields['Thumbnail'] || '',\n      category: r.fields['Category'] || 'General',\n      date: r.fields['Publish Date'] || '',\n      featured: r.fields['Featured'] || false\n    }));\n  }\n\n  function formatDate(d) {\n    if (!d) return '';\n    const dt = new Date(d);\n    return dt.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });\n  }\n\n  function buildFilters(posts) {\n    const cats = ['All', ...new Set(posts.map(p => p.category).filter(Boolean))];\n    return cats.map(c => `<button class=\"filter-btn ${c === activeFilter ? 'active' : ''}\" onclick=\"setFilter('${c}')\">${c}</button>`).join('');\n  }\n\n  function buildFeaturedCard(post) {\n    const url = `https://stayinyourhometoday.com${post.slug}`;\n    return `\n      <div class=\"featured-section\">\n        <div class=\"featured-label\">Featured article</div>\n        <a href=\"${url}\" class=\"featured-card\">\n          <div class=\"featured-img-wrap\">\n            <img src=\"${post.thumbnail}\" alt=\"${post.title}\" loading=\"lazy\">\n            <div class=\"featured-badge\">Featured</div>\n          </div>\n          <div class=\"featured-body\">\n            <div class=\"featured-cat\">${post.category}</div>\n            <h2>${post.title}</h2>\n            <p>${post.description}</p>\n            <div class=\"featured-meta\">\n              <img src=\"/assets/filesafe/68e3e4826a0a9183037c2f85.png\" alt=\"Tiffany Lancaster\">\n              <span><strong>Tiffany Lancaster</strong> · ${formatDate(post.date)}</span>\n            </div>\n            <span class=\"read-btn\">Read article <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"><path d=\"M5 12h14M12 5l7 7-7 7\"/></svg></span>\n          </div>\n        </a>\n      </div>`;\n  }\n\n  function buildPostCard(post, index) {\n    const url = `https://stayinyourhometoday.com${post.slug}`;\n    const delay = (index * 0.07).toFixed(2);\n    return `\n      <a href=\"${url}\" class=\"post-card\" style=\"animation-delay:${delay}s\">\n        <div class=\"post-thumb\">\n          <img src=\"${post.thumbnail}\" alt=\"${post.title}\" loading=\"lazy\">\n          <div class=\"post-cat-badge\">${post.category}</div>\n        </div>\n        <div class=\"post-body\">\n          <h3>${post.title}</h3>\n          <p>${post.description}</p>\n          <div class=\"post-footer\">\n            <span class=\"post-date\">${formatDate(post.date)}</span>\n            <span class=\"post-arrow\">→</span>\n          </div>\n        </div>\n      </a>`;\n  }\n\n  function render(posts) {\n    const featured = posts.find(p => p.featured);\n    const grid = posts.filter(p => !p.featured || activeFilter !== 'All');\n    const filtered = activeFilter === 'All' ? posts : posts.filter(p => p.category === activeFilter);\n    const featuredFiltered = activeFilter === 'All' ? filtered.find(p => p.featured) : null;\n    const gridPosts = featuredFiltered ? filtered.filter(p => !p.featured) : filtered;\n\n    let html = `<div class=\"filters\">${buildFilters(posts)}</div>`;\n\n    if (filtered.length === 0) {\n      html += `<div class=\"empty-state\"><p>No articles in this category yet — check back soon.</p></div>`;\n    } else {\n      if (featuredFiltered) html += buildFeaturedCard(featuredFiltered);\n      if (gridPosts.length > 0) {\n        html += `<div class=\"grid-section\">`;\n        if (featuredFiltered) html += `<div class=\"grid-label\">All articles</div>`;\n        html += `<div class=\"post-count\">Showing <strong>${gridPosts.length}</strong> article${gridPosts.length !== 1 ? 's' : ''}</div>`;\n        html += `<div class=\"posts-grid\">`;\n        html += gridPosts.map((p, i) => buildPostCard(p, i)).join('');\n        html += `</div></div>`;\n      }\n    }\n\n    document.getElementById('blog-root').innerHTML = html;\n  }\n\n  function setFilter(cat) {\n    activeFilter = cat;\n    render(allPosts);\n  }\n\n  async function init() {\n    try {\n      allPosts = await fetchPosts();\n      render(allPosts);\n    } catch (err) {\n      document.getElementById('blog-root').innerHTML = `\n        <div class=\"error-box\">\n          Could not load articles. Please refresh the page or <a href=\"https://stayinyourhometoday.com/contactus\" style=\"color:#7c3aed\">contact us</a> directly.\n        </div>`;\n      console.error(err);\n    }\n  }\n\n  init();\n</script>\n<script defer src=\"https://static.cloudflareinsights.com/beacon.min.js/v833ccba57c9e4d2798f2e76cebdd09a11778172276447\" integrity=\"sha512-57MDmcccJXYtNnH+ZiBwzC4jb2rvgVCEokYN+L/nLlmO8rfYT/gIpW2A569iJ/3b+0UEasghjuZH/ma3wIs/EQ==\" data-cf-beacon='{\"version\":\"2024.11.0\",\"token\":\"d56c0fb9091e40fc8f3829f8a67134fa\",\"server_timing\":{\"name\":{\"cfCacheStatus\":true,\"cfEdge\":true,\"cfExtPri\":true,\"cfL4\":true,\"cfOrigin\":true,\"cfSpeedBrain\":true},\"location_startswith\":null}}' crossorigin=\"anonymous\"></script>\n</body>\n\n<!-- Mirrored from stayinyourhometoday.com/blog by HTTrack Website Copier/3.x [XR&CO'2014], Wed, 10 Jun 2026 19:35:39 GMT -->\n</html></div><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!-